import{_ as e,o as a,c as r,ag as s}from"./chunks/framework.B3IQijK_.js";const u=JSON.parse('{"title":"Pro Trader","description":"MCP-first chart trading persona for experienced Indian market traders using TradingView, Groww, and Kite context.","frontmatter":{"title":"Pro Trader","description":"MCP-first chart trading persona for experienced Indian market traders using TradingView, Groww, and Kite context.","outline":2,"head":[["link",{"rel":"canonical","href":"https://tradecli.in/wiki/guides/pro-trader"}]]},"headers":[],"relativePath":"guides/pro-trader.md","filePath":"guides/pro-trader.md"}'),i={name:"guides/pro-trader.md"};function n(o,t,d,l,p,c){return a(),r("div",null,[...t[0]||(t[0]=[s(`<h1 id="pro-trader" tabindex="-1">Pro Trader <a class="header-anchor" href="#pro-trader" aria-label="Permalink to &quot;Pro Trader&quot;">​</a></h1><p>Pro Trader is built for traders who already understand entries, stops, sizing, and market structure, and want a fast chart-first workflow instead of a teaching flow.</p><p>Use Pro Trader when you want to reason from live market context: TradingView chart state, levels, multi-timeframe structure, momentum, options context, and broker-side position checks.</p><h2 id="what-it-s-for" tabindex="-1">What it&#39;s for <a class="header-anchor" href="#what-it-s-for" aria-label="Permalink to &quot;What it&#39;s for&quot;">​</a></h2><ul><li>Chart-first trade decisions for Indian cash and options markets</li><li>Multi-timeframe structure, support/resistance, VWAP, momentum, and invalidation</li><li>Options buying and selling workflows with explicit bias, levels, and risk</li><li>Pine script workflows for indicators, strategies, and TradingView backtests</li><li>Broker-side context from Groww or Kite when it materially improves the decision</li></ul><p>Pro Trader assumes you can judge trade risk. It will stay concise, decision-oriented, and practical.</p><h2 id="how-it-differs-from-trader" tabindex="-1">How it differs from Trader <a class="header-anchor" href="#how-it-differs-from-trader" aria-label="Permalink to &quot;How it differs from Trader&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Persona</th><th>Best for</th><th>Primary workflow</th></tr></thead><tbody><tr><td><a href="/trading-sandbox-website-preview/wiki/guides/trader">Trader</a></td><td>Streak strategy building, backtesting, deployment, and monitoring</td><td>Browser-driven Streak workflows</td></tr><tr><td><strong>Pro Trader</strong></td><td>Live chart context, trade setup quality, levels, options/cash decisions, Pine tools</td><td>MCP-first TradingView, Groww, and Kite workflows</td></tr></tbody></table><p>If you ask Pro Trader for browser-driven execution, Streak deployment, or Streak strategy monitoring, it should route you back to <a href="/trading-sandbox-website-preview/wiki/guides/trader">Trader</a>.</p><h2 id="primary-tools" tabindex="-1">Primary tools <a class="header-anchor" href="#primary-tools" aria-label="Permalink to &quot;Primary tools&quot;">​</a></h2><ul><li>TradingView Desktop app with at least an Essential paid plan, required for MCP access to charts, screeners, watchlists, Pine state, screenshots, and Strategy Tester results</li><li>A Groww or Zerodha account with MCP access for positions, margin, holdings, and broker context</li><li>An AI provider of your choice to run the workflows</li></ul><p>Pro Trader prefers MCP-native workflows over browser detours. For trade discovery and scanning, it prefers TradingView screeners before broker screeners.</p><p>Best for: traders who already know what they&#39;re doing and want a fast, chart-native second pair of eyes — not hand-holding.</p><h2 id="trade-path-routing" tabindex="-1">Trade path routing <a class="header-anchor" href="#trade-path-routing" aria-label="Permalink to &quot;Trade path routing&quot;">​</a></h2><p>For trade intent, Pro Trader resolves the missing parts of the trade path before analyzing the setup:</p><table tabindex="0"><thead><tr><th>Axis</th><th>Examples</th></tr></thead><tbody><tr><td>Underlying</td><td>NIFTY, BANKNIFTY, RELIANCE, a sector, a watchlist</td></tr><tr><td>Instrument</td><td>Cash, futures, options</td></tr><tr><td>Style</td><td>Intraday, swing, positional</td></tr><tr><td>Exposure</td><td>Long, short, range, volatility, hedge</td></tr><tr><td>Strategy</td><td>Breakout, pullback, mean reversion, event, theta harvest</td></tr><tr><td>Product</td><td>CNC, MIS, MTF, NRML</td></tr><tr><td>Execution</td><td>Discretionary, rule-based, systematic, semi-auto</td></tr></tbody></table><p>If one axis is missing, Pro Trader asks one focused question at a time instead of dumping a long intake form.</p><h2 id="pine-workflows" tabindex="-1">Pine workflows <a class="header-anchor" href="#pine-workflows" aria-label="Permalink to &quot;Pine workflows&quot;">​</a></h2><p>Pro Trader includes Pine script and backtest workflows for TradingView.</p><p>Useful prompts:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Show me the Pine script catalog</span></span>
<span class="line"><span>Use VWAP and Auto S/R to review this chart</span></span>
<span class="line"><span>Backtest the strategy already on my chart</span></span>
<span class="line"><span>Create a Pine strategy for this breakout setup</span></span>
<span class="line"><span>Stress-test this backtest for repaint or overfit risk</span></span></code></pre></div><p>High-leverage Pine adapters include IntraEdge, Sentient Level, VWAP, F&amp;O Time Zones, Auto Price Action S/R Levels, TTM Squeeze, SuperTrend + ADX, and Momentum Breakout.</p><h2 id="typical-prompts" tabindex="-1">Typical prompts <a class="header-anchor" href="#typical-prompts" aria-label="Permalink to &quot;Typical prompts&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Read my BANKNIFTY 5m chart and give me bias, levels, invalidation</span></span>
<span class="line"><span>Is this NIFTY breakout trade worth taking?</span></span>
<span class="line"><span>Build an options plan for a range-bound BANKNIFTY session</span></span>
<span class="line"><span>Scan TradingView for liquid cash breakouts with clean structure</span></span>
<span class="line"><span>Review my RELIANCE swing setup across 15m, 1h, and daily</span></span>
<span class="line"><span>Run Strategy Tester on the Pine strategy on my chart and flag red risks</span></span></code></pre></div><div class="danger custom-block"><p class="custom-block-title">Guardrails</p><p>Pro Trader must not fabricate option-chain data, margin, positions, fills, Greeks, OI, or order status. It must not claim an order was placed or managed unless a broker tool confirms it.</p></div><h2 id="what-s-next" tabindex="-1">What&#39;s next <a class="header-anchor" href="#what-s-next" aria-label="Permalink to &quot;What&#39;s next&quot;">​</a></h2><ul><li><strong>Compare with other personas</strong> → <a href="/trading-sandbox-website-preview/wiki/guides/personas">Personas &amp; Modes</a></li><li><strong>Set up TradingView browser context</strong> → <a href="./../getting-started/browser-setup">Browser Setup</a></li><li><strong>Use Streak automation instead</strong> → <a href="/trading-sandbox-website-preview/wiki/guides/trader">Trader</a></li></ul>`,27)])])}const g=e(i,[["render",n]]);export{u as __pageData,g as default};
